// ==============================
// VAR, LET, CONST
// ==============================

// var -> old way (avoid mostly)
var accountName = "Yash"

// let -> value can change
let accountEmail = "yash@gmail.com"

// const -> value cannot change
const accountId = 12345

// Reassigning let
accountEmail = "new@gmail.com"

// Reassigning const ❌
// accountId = 999

console.log(accountName)
console.log(accountEmail)
console.log(accountId)


// ==============================
// Scope Difference
// ==============================

if (true) {
    var a = 10
    let b = 20
    const c = 30
}

console.log(a) // works

// console.log(b) ❌
// console.log(c) ❌


// ==============================
// WHY VAR IS AVOIDED
// ==============================

// var ignores block scope

var test = 100

if (true) {
    var test = 200
}

console.log(test) // 200 (unexpected sometimes)


// let is safer

let value = 50

if (true) {
    let value = 100
    console.log(value) // 100
}

console.log(value) // 50

// ==============================
// PRIMITIVE DATATYPES
// ==============================

// String
let name = "Yash"

// Number
let age = 25

// Boolean
let isLoggedIn = true

// Null
let temperature = null

// Undefined
let state

// Symbol
let id = Symbol('123')

// BigInt
let bigNumber = 12345678901234567890n


// ==============================
// TYPEOF CHECKING
// ==============================

console.log(typeof name)         // string
console.log(typeof age)          // number
console.log(typeof isLoggedIn)   // boolean
console.log(typeof temperature)  // object (famous JS bug)
console.log(typeof state)        // undefined


// ==============================
// NON-PRIMITIVE DATATYPES
// ==============================

// Array
let heroes = ["Ironman", "Thor", "Spiderman"]

// Object
let user = {
    username: "Yash",
    age: 25
}

// Function
function greet() {
    console.log("Hello")
}

console.log(typeof heroes) // object
console.log(typeof user)   // object
console.log(typeof greet)  // function

// ==========================================================
// JAVASCRIPT STACK & HEAP MEMORY
// ==========================================================

/*
JavaScript mainly uses 2 types of memory:

1. Stack Memory
2. Heap Memory
*/

// ==========================================================
// PRIMITIVE DATATYPES → STACK MEMORY
// ==========================================================

let myYoutubeName = "hiteshchaudhary"
let anotherName = myYoutubeName

anotherName = "chaiAurCode"

console.log(myYoutubeName) // hiteshchaudhary
console.log(anotherName)   // chaiAurCode


// ==========================================================
// NON-PRIMITIVE DATATYPES → HEAP MEMORY
// ==========================================================

let userOne = {
    email: "yash@gmail.com",
    upi: "yash@ybl"
}

let userTwo = userOne

userTwo.email = "new@gmail.com"

console.log(userOne.email) // new@gmail.com
console.log(userTwo.email) // new@gmail.com


// ==========================================================
// HOW TO CREATE REAL COPY
// ==========================================================

let originalUser = {
    name: "Yash",
    age: 25
}

let copiedUser = { ...originalUser }
copiedUser.name = "Prime"

console.log(originalUser.name) // Yash
console.log(copiedUser.name)   // Prime

// ==========================================================
// STRING DECLARATION
// ==========================================================

const name = "hitesh"
const repoCount = 50

// Modern way - Template Literals
console.log(`Hello my name is ${name} and my repo count is ${repoCount}`)


// ==========================================================
// STRING OBJECT & METHODS
// ==========================================================

const gameName = new String('hitesh-hc-com')

console.log(gameName[0])           // h
console.log(gameName.length)       // 14
console.log(gameName.toUpperCase())
console.log(gameName.charAt(2))    // t
console.log(gameName.indexOf('t')) // 2


// ==========================================================
// IMPORTANT STRING METHODS
// ==========================================================

const newString = gameName.substring(0, 4)
console.log(newString) // hite

console.log(gameName.slice(-8, 4))

// trim
const newStringOne = "   hitesh    "
console.log(newStringOne.trim())

// replace
const url = "https://hitesh.com/hitesh%20choudhary"
console.log(url.replace('%20', '-'))

// includes & split
console.log(url.includes('hitesh'))
console.log(gameName.split('-'))

// ==========================================================
// NUMBER CONVERSION & OPERATIONS
// ==========================================================

let score = "33"
let valueInNumber = Number(score)
console.log(valueInNumber)

// NaN Case
let score2 = "33abc"
let value2 = Number(score2)
console.log(value2) // NaN

console.log(Number(null))      // 0
console.log(Number(undefined)) // NaN
console.log(Number(true))      // 1


// ==========================================================
// MATH OBJECT
// ==========================================================

console.log(Math.random())
console.log(Math.floor(Math.random() * 10) + 1)

const min = 10
const max = 20

console.log(Math.floor(Math.random() * (max - min + 1)) + min)

console.log(Math.round(4.6))
console.log(Math.ceil(4.2))
console.log(Math.floor(4.9))

// ==========================================================
// DATES IN JAVASCRIPT
// ==========================================================

let myDate = new Date()
console.log(myDate.toString())
console.log(myDate.toDateString())
console.log(myDate.toLocaleString())

// Creating custom dates
let dateOne = new Date(2023, 0, 23)
console.log(dateOne.toDateString())

let myTimeStamp = Date.now()
console.log(myTimeStamp)

// Fix: declared newDate
let newDate = new Date()
console.log(newDate.getMonth() + 1)
console.log(newDate.getDay())


